import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Chemical = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // Category 'chemical' ke liye data fetch karna
  useEffect(() => {
    const fetchChemicalPosts = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/blog/chemical');
        setPosts(res.data);
      } catch (err) {
        console.error("Chemical posts fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchChemicalPosts();
  }, []);

  return (
    <div className="bg-white antialiased w-full">

      {/* 1. FULL WIDTH HEADER */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-r from-[#0F1F1C] to-[#112E2A] text-white">
        <div className="w-full">
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter mb-6">
            Chemical <span className="text-orange-400">Solutions</span>
          </h1>
          <p className="text-orange-100 text-lg md:text-xl font-light max-w-3xl leading-relaxed">
            Sourcing specialized talent for petrochemicals, laboratory research, and large-scale industrial chemical processing.
          </p>
        </div>
      </section>

      {/* 2. DYNAMIC SPOTLIGHT SECTION */}
      <section className="w-full bg-white border-t border-gray-100">
        <div className="py-16 px-6 md:px-16 w-full bg-gray-50 flex justify-between items-end">
          <div>
            <h2 className="text-5xl font-black text-gray-900 tracking-tighter">
              Industrial <span className="text-orange-600">Spotlight</span>
            </h2>
            <div className="h-1.5 w-24 bg-orange-500 mt-4 rounded-full"></div>
          </div>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest hidden md:block">
            Global Chemical Operations
          </p>
        </div>

        <div className="w-full flex flex-col">
          {loading ? (
            <div className="py-32 text-center text-gray-400 font-black animate-pulse uppercase tracking-[0.2em]">
              Synchronizing Chemical Database...
            </div>
          ) : posts.length > 0 ? (
            posts.map((post, index) => (
              <div 
                key={post._id || index} 
                className="w-full px-6 md:px-16 py-16 flex flex-col md:flex-row items-center gap-12 border-b border-gray-100 last:border-b-0 hover:bg-orange-50/20 transition-colors group"
              >
                {/* Left Side: Media */}
                <div className="flex-shrink-0">
                  <div className="h-44 w-44 bg-white border-2 border-orange-100 rounded-[2.5rem] flex items-center justify-center text-7xl shadow-2xl overflow-hidden relative">
                    {post.image ? (
                      <img src={post.image} alt={post.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                    ) : (
                      <span className="text-orange-500 group-hover:scale-110 transition-transform">⚗️</span>
                    )}
                  </div>
                </div>

                {/* Right Side: Content */}
                <div className="flex-grow">
                  <div className="flex items-center gap-4 mb-4">
                    <span className="bg-orange-600 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-tighter">
                      Industry Update
                    </span>
                    <span className="text-gray-400 font-bold text-[10px] uppercase tracking-widest">
                      {post.date || 'April 2026'}
                    </span>
                  </div>
                  <h3 className="text-3xl md:text-4xl font-black text-gray-950 mb-4 tracking-tighter group-hover:text-orange-600 transition-colors">
                    {post.title}
                  </h3>
                  <div className="relative">
                    <p className="text-gray-700 text-xl leading-relaxed italic max-w-5xl">
                      "{post.description}"
                    </p>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="py-32 px-16 text-gray-400 text-xl font-medium italic">
              No chemical industrial posts currently live.
            </div>
          )}
        </div>
      </section>

      {/* 3. FULL WIDTH CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="w-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-[4rem] p-12 md:p-20 flex flex-col md:flex-row items-center justify-between text-white shadow-2xl shadow-orange-100 relative overflow-hidden">
          <div className="absolute -bottom-10 -left-10 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>

          <div className="md:w-2/3 relative z-10">
            <h2 className="text-4xl md:text-6xl font-black mb-6 tracking-tighter leading-tight">
              Start Your Career <br /> With Hudson Today
            </h2>
            <p className="text-orange-50 text-xl mb-10 max-w-xl font-medium">
              We're looking for chemical engineers, lab technicians, and safety officers for global projects.
            </p>
            <Link to="/careers">
              <button className="bg-white text-orange-600 px-12 py-5 rounded-2xl font-black text-xl hover:bg-gray-900 hover:text-white transition-all shadow-xl active:scale-95">
                Apply Now
              </button>
            </Link>
          </div>

          <div className="hidden md:flex md:w-1/3 justify-end relative z-10">
            <div className="h-64 w-64 border-4 border-orange-400/30 rounded-full flex items-center justify-center animate-bounce duration-[3000ms]">
               <span className="text-8xl opacity-30">🧪</span>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Chemical;
